class NetworkListener(receiverActor: ActorRef, port: Int) extends Thread {
  setDaemon(true)
  
  override def run(): Unit = {
    val serverSocket = new ServerSocket(port)
    println(s"Network listener started on port $port")
    
    while (true) {
      try {
        val clientSocket = serverSocket.accept()
        println(s"Accepted connection from ${clientSocket.getInetAddress}")
        
        new Thread(() => handleClient(clientSocket)).start()
      } catch {
        case ex: Exception =>
          println(s"Error accepting connection: ${ex.getMessage}")
      }
    }
  }
  
  def handleClient(socket: Socket): Unit = {
    try {
      val input = socket.getInputStream
      val buffer = new Array[Byte](8192)
      
      var bytesRead = input.read(buffer)
      while (bytesRead != -1) {
        val payload = buffer.take(bytesRead)
        receiverActor ! NetworkMessage(payload)
        bytesRead = input.read(buffer)
      }
    } catch {
      case ex: Exception =>
        println(s"Error handling client: ${ex.getMessage}")
    } finally {
      socket.close()
    }
  }
}

